/**
 * Sparkline's x-axis subcomponent props
 * @public
 */
export interface SparklineXAxisProps {
    /**
     * The min value configuration to display in the axis
     * @defaultValue 'auto'
     */
    min?: 'auto' | 'data-min' | number | Date;
    /**
     * The max value configuration to display in the axis
     * @defaultValue 'auto'
     */
    max?: 'auto' | 'data-max' | number | Date;
}
/**
 * Sparkline's internal required x-axis props
 * @internal
 */
export interface SparklineXAxisInternalProps {
    /**
     * The min value configuration to display in the axis
     */
    min: 'data-min' | Date;
    /**
     * The max value configuration to display in the axis
     */
    max: 'data-max' | Date;
}
